import { getPitchRange } from "../appData.js";

export const level13 = {
  num: 13, name: "Song Interpretation", focus: "Learn by ear, transcription, style absorption, repertoire building",
  duration: "40 min",
  setup: "Phone/speaker for reference tracks. Guitar. Recording setup.",
  subtitle: "Song Interpretation",
  description: "The fastest way to grow as a singer is to learn songs by ear. Not from tabs, not from YouTube tutorials -- by LISTENING and figuring it out with your voice and your guitar. This level teaches a systematic learn-by-ear methodology backed by research on how expert musicians internalize new material. The neuroscience is clear: when you figure out a melody by ear, you're building direct connections between your auditory cortex (hearing) and your motor cortex (singing/playing). When you read from a tab or follow a tutorial, you're routing through your visual cortex instead -- a detour that produces weaker musical memory and less flexible recall. You'll learn songs from Gene's artists -- Allah-Las, Khruangbin, DOPE LEMON, Skinshape -- not just the notes, but the DELIVERY. Because delivery is what makes a cover sound like an interpretation instead of karaoke. The difference between singing the notes and singing the SONG is the difference between reading a script and acting.",
  artists: "Allah-Las, DOPE LEMON, Skinshape, Khruangbin",
  unlocks: "Performance & Integration (Level 14)",
  review: { label: "Level 11 Check-In", time: 5, exercises: ["v11e3", "v11e9"], prompt: "Sing Dorian over a reggae groove (v11e3). Then improvise modally for 2 minutes (v11e9). Modal awareness needs regular practice -- it fades without use." },
  exercises: [
    {
      id: "v13e0", time: 3, title: "Diagnostic: How Do You Learn Songs?", type: "record",
      what: "Assess your current song-learning method. Do you use tabs? YouTube tutorials? Do you figure out melodies by ear? This diagnostic reveals the gaps in your learn-by-ear skill set and creates a baseline for measuring growth through the level.",
      setup: "Phone or speaker with a song you DON'T already know. Something from your playlist that you've heard but never learned. Guitar nearby but don't touch it yet.",
      referencePitches: getPitchRange("E3", "A4"),
      pianoKeys: { notes: ["E3", "A3", "C4", "E4"], label: "Song Reference", range: ["E3", "E4"] },
      recorder: true,
      steps: [
        { text: "Pick a song you've heard many times but never learned to play or sing. Something from your regular rotation -- an Allah-Las track, a Skinshape tune, a DOPE LEMON song. Press play and just listen to the first verse and chorus. Don't do anything else. Just listen.", why: "Starting with a familiar-but-unlearned song reveals the gap between passive listening and active musical knowledge. You've heard this song dozens of times, but can you sing the melody accurately from memory? Can you identify the chord changes? The gap between 'I know this song' and 'I can perform this song' is exactly what this level closes. Research on music perception shows that casual listeners encode the FEELING of a song (tempo, mood, key) but not the DETAILS (exact melody, chord voicings, rhythmic patterns). Active learning converts feeling-level knowledge into performance-level knowledge." },
        { text: "Now, without the song playing, try to sing the vocal melody of the verse from memory. Record yourself. How accurate is it? Can you get the first few notes? The whole verse? The rhythm? Most people discover they know the VIBE but not the actual NOTES.", why: "This test reveals the depth of your current musical memory. If you can sing the first few notes but lose the melody by the third bar, that's typical -- passive listening encodes melodic contour (the general shape: up, down, up) but not precise intervals. If you can sing the whole verse accurately, your ear is more developed than you realize. Either way, the recording gives you a measurable starting point. You'll repeat this test with a NEW song at the end of Level 13 to see how much your by-ear learning speed has improved." },
        { text: "Try to find the starting note of the melody on your guitar. Just the first note. How long does it take? Seconds? Minutes? If you can do it quickly, your relative pitch is strong. If it takes a while (or you can't find it), that's the specific skill this level trains.", why: "Finding a pitch on your instrument by ear is the bridge between hearing and playing. It requires RELATIVE PITCH -- the ability to hear a note and locate it on your instrument by comparing it to known references. Unlike perfect pitch (which is rare and largely innate), relative pitch is entirely trainable. Every time you successfully match a heard note to a fretted note, you strengthen the neural pathway between auditory recognition and motor execution. Speed of pitch-matching is the best single predictor of by-ear learning ability." },
        { text: "Rate yourself 1-5 on each dimension: Melodic recall (can you sing back what you heard?). Pitch matching (can you find notes on guitar?). Chord identification (can you hear chord changes?). Rhythmic accuracy (can you reproduce the vocal rhythm?). Style recognition (can you describe HOW the singer delivers the melody?). Write down your scores.", why: "These five dimensions correspond to the five skill areas this level trains. Melodic recall is trained by the 6-step method (v13e1). Pitch matching is trained by melodic dictation (v13e3). Chord identification develops through repeated by-ear learning. Rhythmic accuracy comes from focused listening (v13e2). Style recognition is the focus of the absorption exercises (v13e4, v13e5). Your lowest score is your biggest opportunity for growth." },
        { text: "Reflect on your current process: when you want to learn a song, what do you do FIRST? Google the chords? Open YouTube? Or listen and figure it out? Be honest. There's no wrong answer, but there IS a more effective method -- and this level teaches it.", why: "Self-awareness about your learning habits is the foundation of changing them. Most guitar players default to looking up tabs because it's faster in the short term. But faster learning leads to weaker memory and less flexible recall. The by-ear approach is slower initially but produces deeper learning -- what researchers call 'desirable difficulty.' The effort of figuring something out yourself creates stronger neural connections than the ease of reading someone else's answer. This is the same principle behind why students who take notes by hand retain more than those who type." },
        { text: "Save your scores and recordings. At the end of Level 13, you'll learn a completely new song by ear and reassess all five dimensions to measure your growth.", why: "The pre/post comparison is the most convincing evidence of skill development because it controls for song difficulty and personal taste. You'll use the exact same rating scale on a different song, which isolates your skill improvement from familiarity effects. Most students show 1-3 point improvements across dimensions after completing this level, with the biggest gains in melodic recall and pitch matching -- the two skills that improve most dramatically with deliberate practice." }
      ],
      feel: "This should feel like an honest self-assessment -- no judgment, just information. Whether you score 1s or 5s, you now have a clear picture of where you are and where this level will take you.",
      wrong: "If you picked a song you already know well, pick a different one -- the diagnostic only works with songs you haven't actively learned. If you can't find the starting note on guitar at all, that's fine -- it means this level will produce dramatic improvement for you.",
      sarah: "Gene, most musicians never systematically assess their by-ear skills because it feels vulnerable -- like admitting you can't do something you 'should' be able to do. But honestly evaluating where you are is the single most effective thing you can do for your musical growth. Your years of deep listening to Khruangbin, Skinshape, and the rest have filled your ear with an enormous library of melodic and rhythmic patterns. This level teaches you to ACCESS that library actively instead of just enjoying it passively.",
      levelUp: "Completed diagnostic with honest self-assessment scores across all 5 dimensions, baseline recording saved for comparison."
    },
    {
      id: "v13e1", time: 5, title: "The 6-Step Learn-By-Ear Method", type: "vocal",
      what: "A systematic process for learning any song by ear, backed by research on expert musician learning strategies. These 6 steps transform the vague process of 'figuring it out' into a repeatable, reliable method that gets faster with practice.",
      setup: "Phone/speaker with target song queued. Guitar. Paper and pen for notes. Quiet space where you can replay sections repeatedly.",
      referencePitches: getPitchRange("E3", "A4"),
      pianoKeys: { notes: ["E3", "A3", "C4", "E4"], label: "Song Reference", range: ["E3", "E4"] },
      recorder: true,
      steps: [
        { text: "Step 1: LISTEN 3x without doing anything. Full song, no pausing, no guitar, no singing along. First listen: notice the overall form (verse, chorus, bridge, how many sections?). Second listen: focus on the vocal melody (where does it go up? down? how high does it get?). Third listen: focus on the accompaniment (what instruments? what rhythm? what key feeling?).", why: "Three full listens before any active engagement is the single most important habit in by-ear learning. Research on expert musicians (Woody & Lehmann, 2010) found that professionals spend significantly more time LISTENING before attempting to play than amateurs do. Amateurs grab their instrument after 30 seconds and start guessing; professionals listen to the entire piece multiple times first. The three-listen protocol (form -> melody -> accompaniment) is a structured version of this expert behavior. Each listen has a different focus, which prevents the brain from trying to process everything at once -- a strategy called 'selective attention' that dramatically improves information encoding." },
        { text: "Step 2: HUM ALONG. Play the song again and hum the vocal melody. Not perfectly -- approximately. Feel the contour: where does it rise? Where does it fall? Where does it repeat? Where does it surprise you? Hum the verse melody 3 times. Then hum the chorus melody 3 times. You're building a MOTOR MEMORY of the melody in your vocal cords, separate from the auditory memory in your ear.", why: "Humming engages the motor cortex, converting passive listening into active physical engagement. Research on embodied cognition shows that physical engagement with music (even approximate humming) creates stronger memory traces than listening alone. The motor memory is stored in a different brain region than the auditory memory, which means you're creating TWO memory traces for the same melody -- redundancy that makes recall more reliable. The focus on contour (up/down/repeat/surprise) is important because melodic contour is the first thing the brain encodes about a melody, before exact intervals." },
        { text: "Step 3: FIND THE TONIC. Pick up your guitar. Find the 'home note' of the song -- the note that feels like resolution, like the end of a journey. Play random notes until one feels like 'home.' Then check: is the song in a major key or minor? Play a major chord and a minor chord on that root note. Which one matches? This gives you the key of the song.", why: "The tonic (home note) is the harmonic anchor of the entire song. Once you know the tonic, every other note can be understood in relation to it: 'one step above home,' 'a big leap below home,' etc. This relational understanding is faster and more reliable than finding each note independently. The ability to identify the tonic is a core skill of musical ear training -- it's the difference between navigating with a map (knowing where home is) and navigating blind (finding each note from scratch). For most pop, rock, and folk songs, the tonic is the first or last note of the vocal melody, or the root of the first or last chord." },
        { text: "Step 4: MAP SCALE DEGREES. Sing the melody slowly, one phrase at a time. For each note, identify its relationship to the tonic: is it the tonic itself (1)? One step up (2)? A big leap up to 5? You don't need formal solfege -- just numbers or feelings. 'Home, one up, two up, jump up, back to home.' Find each note on your guitar to confirm.", why: "Scale degree mapping transforms a sequence of absolute pitches into a sequence of RELATIONSHIPS, which is how your brain naturally encodes melodies. Research on melodic memory shows that musicians remember melodies as scale-degree sequences, not as absolute pitches -- which is why you can sing a song in any key. By consciously mapping the scale degrees, you're aligning your explicit knowledge with your implicit knowledge. The guitar serves as a pitch reference -- when your voice sings a note and your guitar confirms it, the match reinforces both the auditory and motor memory. Over time, this process gets faster because you develop familiarity with common scale-degree patterns (like 1-3-5 or 5-4-3-2-1)." },
        { text: "Step 5: MICROLOOP. Isolate 2-4 bar sections and learn them one at a time. Play the section on your phone, pause, sing it back, check on guitar. Repeat until you can sing the section accurately without the reference. Then move to the next section. Don't try to learn the whole song at once -- eat it in small bites.", why: "Microlooping is the most efficient learning strategy because it exploits the brain's working memory capacity. Working memory can hold approximately 4-7 'chunks' of information at a time. A 2-4 bar section contains roughly that many melodic events, making it the ideal unit for learning. Trying to learn longer sections overwhelms working memory and leads to errors that get practiced (and therefore learned). The pause-and-sing-back technique is called 'retrieval practice' in cognitive science, and it's been shown to be significantly more effective than repeated listening for long-term retention. Each successful retrieval strengthens the memory trace." },
        { text: "Step 6: ASSEMBLE. Sing the full verse from memory (no reference track). Then the chorus. Then verse + chorus together. Then add the bridge or other sections. Build the complete song from the microlooped sections, like assembling a puzzle from pieces you've already studied individually.", why: "Assembly is the final step because it tests LONG-TERM memory and SEQUENTIAL RECALL -- the ability to remember not just each section but the ORDER of sections. This is a different memory challenge than learning individual sections because it requires 'chunking' at a higher level: each section becomes a single unit in a larger sequence. The progressive assembly (verse alone, chorus alone, verse+chorus, full song) builds this hierarchical memory structure gradually. Research on musical memorization shows that this bottom-up assembly approach produces more reliable recall than trying to learn the song from start to finish, because each section is independently secure before it's connected to the next." },
        { text: "Now sing the full section with guitar accompaniment. If you figured out the chords during Step 3-4, play along. If not, just strum the tonic chord as a drone. The goal is voice + guitar performing a learned-by-ear song. Record yourself and compare to the original.", why: "Adding guitar accompaniment is the integration step that transforms ear-learning from an academic exercise into a performance skill. The comparison to the original is important but shouldn't be demoralizing -- you're not trying to create a perfect copy. You're trying to capture the essence: the melody, the rhythm, the harmonic structure, the feel. Differences between your version and the original aren't errors; they're the beginning of your INTERPRETATION. The notes you get 'wrong' might actually be choices your ear prefers. Pay attention to those moments -- they're your musical personality asserting itself." }
      ],
      feel: "Steps 1-2 should feel patient and receptive -- you're absorbing, not producing. Steps 3-4 should feel like detective work -- you're solving a puzzle with your ear and your guitar. Step 5 should feel methodical -- small pieces, repeated until solid. Step 6 should feel triumphant -- you learned a song BY EAR, from scratch, with no tabs or tutorials.",
      wrong: "If you're tempted to look up the chords: DON'T. The struggle of figuring it out IS the exercise. The desirable difficulty is what makes the learning stick. If you truly can't find the key, try: play every note on one string until one sounds like 'home.' If you can't isolate the vocal melody from the accompaniment, try listening on headphones with the balance shifted to one side.",
      sarah: "Gene, this method will feel slow the first time you use it. A song that takes 5 minutes to learn from a YouTube tutorial might take 30 minutes to learn by ear. But here's what the research shows: the by-ear version will still be in your memory a month later. The YouTube version will be gone in a week. You're investing 25 extra minutes for 30x better retention. That's the best deal in music education.",
      metronome: 80,
      levelUp: "Complete song section (verse + chorus) learned entirely by ear using the 6-step method, performed with guitar accompaniment from memory."
    },
    {
      id: "v13e2", time: 4, title: "Active Listening: The Mirror Neuron Method", type: "listen",
      what: "Listen to a target song 5 times with different focus each time. Not casual listening -- ACTIVE listening with a specific assignment for each pass. Research shows that focused repetitive listening activates mirror neurons that prepare your motor system to replicate what you hear. You're literally training your brain to sing the song WHILE you're listening to it.",
      setup: "Target song queued. Headphones strongly recommended -- you need to hear details. Comfortable position. Paper and pen for notes between listens.",
      referencePitches: getPitchRange("E3", "A4"),
      pianoKeys: { notes: ["E3", "A3", "C4", "E4"], label: "Song Reference", range: ["E3", "E4"] },
      steps: [
        { text: "Listen 1: FEEL. Don't analyze anything. Just receive the song as an emotional experience. Notice: what mood does it create? Where does it feel tense? Where does it release? What's the overall energy arc (does it build, stay steady, ebb and flow)? Write 3 words that describe the feeling.", why: "The emotional listen comes first because music is fundamentally an emotional communication medium. If you start by analyzing intervals and chord progressions, you miss the forest for the trees. The 3-word exercise forces you to crystallize your emotional response, which becomes the interpretive compass for your performance. When you eventually sing this song, those 3 words should guide your delivery: if the song feels 'warm, lazy, golden,' your voice should communicate warmth, laziness, and golden-hour light. This emotion-first approach comes from acting pedagogy -- actors identify the emotional core of a scene before working on the technical delivery." },
        { text: "Listen 2: VOCAL MELODY only. Try to hear ONLY the singer's voice. Ignore everything else -- guitar, drums, bass, production. Follow the melody like a line drawn in the air. Notice: where does it go highest? Lowest? Where does it repeat the same phrase? Where does it do something unexpected?", why: "Selective auditory attention is a trainable skill, and isolating the vocal from the mix is one of its most useful applications. When you focus exclusively on the vocal melody, you engage a neural process called 'auditory stream segregation' -- the brain's ability to separate one sound source from a complex mixture. This skill improves dramatically with practice and is essential for by-ear learning because the vocal melody is usually what you're trying to learn. The spatial/contour observations (highest, lowest, repetitions, surprises) create a mental MAP of the melody that guides the learning process." },
        { text: "Listen 3: VOCAL DELIVERY. Same vocal line, but now focus on HOW the singer delivers it, not WHAT they sing. Timing: do they sit behind the beat or push ahead? Dynamics: where do they get quiet? Loud? Texture: is the voice breathy, full, raspy, smooth? Vibrato: where do they use it? Where do they avoid it? Phrasing: where do they breathe? How do they end phrases?", why: "Delivery is what separates interpretation from karaoke. Two singers can sing the same notes with the same rhythm and sound completely different because of delivery choices. This listen trains you to hear delivery as a SEPARATE DIMENSION from melody -- a distinction that most casual listeners never make consciously. Mirror neuron research (Rizzolatti & Craighero, 2004) shows that observing (or hearing) someone perform an action activates the same motor regions in your brain that would be active if YOU were performing it. By focusing on delivery details, you're priming your own vocal motor system to replicate those delivery choices." },
        { text: "Listen 4: GUITAR PART. Now shift focus to the accompaniment. What's the strumming or picking pattern? What are the chord changes? Are they simple or complex? How does the guitar relate to the vocal -- does it follow, contrast, or complement? Can you feel where the chord changes happen in your body?", why: "Understanding the accompaniment gives you the harmonic and rhythmic context for the vocal melody. Many vocal melodies are intimately connected to the guitar part -- certain notes are emphasized BECAUSE they align with chord changes, and certain rhythmic choices make sense ONLY in relation to the guitar pattern. When you learn the song, knowing the accompaniment helps you reconstruct the melody because you can reason: 'the chord changed to G here, so the melody probably hits a B or D.' This contextual knowledge makes by-ear learning faster and more accurate." },
        { text: "Listen 5: THE INTERACTION. This is the integration listen. How do voice and guitar work together? Where does the voice follow the guitar's rhythm? Where does it deliberately go against it? Are there moments where the voice and guitar are in sync (unison rhythm) and moments where they're independent? This is the arrangement -- how two instruments share the musical space.", why: "The voice-guitar interaction is what you'll eventually need to perform, so hearing it clearly is essential for accurate learning. Most singer-songwriters don't consciously plan the interaction between voice and guitar -- it emerges from habit. By analyzing it in songs you admire, you learn arrangement principles that you can apply to your own music. The sync/independence alternation is particularly important: moments of rhythmic unison between voice and guitar feel powerful and unified; moments of independence feel free and conversational. Great singer-songwriters shift between these modes instinctively." },
        { text: "After all 5 listens: write a one-paragraph 'performance brief' -- a description of how you would perform this song. Include the emotional core (from Listen 1), the melodic high/low points (Listen 2), the delivery choices you'd adopt (Listen 3), the guitar approach (Listen 4), and the voice-guitar relationship (Listen 5). This brief becomes your interpretation guide.", why: "The performance brief synthesizes all five listens into an actionable plan. It transforms passive analysis into active intention. When you sit down to learn and perform the song, this brief tells you not just WHAT to play but HOW to play it and WHY certain choices matter. Professional musicians call this 'learning the song behind the song' -- understanding the artistic decisions that shaped the recording, not just the notes. This depth of understanding is what produces interpretations that feel lived-in rather than sight-read." }
      ],
      feel: "Each listen should feel like putting on a different pair of glasses -- you hear the same song but notice different things each time. By Listen 5, you should feel like you KNOW this song at a level you've never known a song before. Not 'I've memorized it' but 'I understand it.'",
      wrong: "If you can't isolate the vocal from the mix (Listen 2), try listening on headphones and focusing on the center of the stereo image -- vocals are almost always panned center. If you can't hear the guitar part separately (Listen 4), try listening on a laptop speaker -- small speakers often emphasize midrange (guitar) frequencies. If the whole process feels tedious, remember: you're building listening skills that will make every future song easier to learn.",
      sarah: "Gene, this exercise is going to change how you hear music forever. Once you start listening with this level of focus, you can't go back to casual hearing. You'll start noticing delivery choices, guitar patterns, and voice-instrument interactions in every song you hear -- in the car, in a cafe, everywhere. That heightened listening is your secret weapon as a musician. It's what your favorite artists developed over years of obsessive listening. You're doing the same thing, just with a structure to accelerate it.",
      levelUp: "Completed 5-focus listening protocol with written performance brief that demonstrates deep understanding of melody, delivery, accompaniment, and voice-guitar interaction."
    },
    {
      id: "v13e3", time: 4, title: "Melodic Dictation", type: "vocal",
      what: "Listen to a 4-bar melody from one of Gene's artists. Without the music playing: hum it back, find the starting note on guitar, figure out each note, map the scale degrees, and sing it from your transcription. This builds the ear-to-voice-to-instrument neural pathway that is the foundation of all by-ear musicianship.",
      setup: "Phone/speaker with song cued to a clear vocal section. Guitar. Paper and pen. This is a focused ear-training exercise -- minimize distractions.",
      referencePitches: getPitchRange("E3", "A4"),
      pianoKeys: { notes: ["E3", "A3", "C4", "E4"], label: "Song Reference", range: ["E3", "E4"] },
      pitchContour: true,
      recorder: true,
      steps: [
        { text: "Listen to a 4-bar vocal phrase from your target song. Play it 3 times. On the third listen, hum along and try to match the melody exactly. Then STOP the music.", why: "Three repetitions is the optimal number for initial encoding: the first listen captures the general shape, the second listen corrects the details, and the third listen (with humming) engages motor memory. Stopping the music after three listens is crucial because the next steps test RECALL, not recognition. Recall (generating the melody from memory) is much harder than recognition (hearing the melody and confirming it matches) but produces far stronger learning. This is the testing effect -- one of the most robust findings in learning science." },
        { text: "From memory, hum the 4-bar phrase back. Record yourself humming. Don't worry about getting every note -- capture the contour (the shape of the melody) first. Is it mostly stepwise? Does it have big leaps? Where's the peak (highest point)? Where's the nadir (lowest point)?", why: "Contour-first reconstruction leverages how the brain naturally encodes melodies. Research on musical memory shows that melodic contour (the pattern of ups and downs) is the most salient feature of a melody -- it's what you remember first and forget last. By getting the contour right first, you create a framework that the exact intervals can fill in. Think of it like drawing: you sketch the outline before adding details. If the contour is right, most of the notes will be close to correct already." },
        { text: "Pick up your guitar. Find the starting note of the melody. Play notes in the general area until one matches what's in your head. Sing the note while playing it to confirm the match. This is pitch matching -- the fundamental ear-training skill.", why: "Pitch matching between voice and instrument creates a three-way neural connection: your auditory cortex (hearing the note in your memory), your motor cortex for voice (singing the note), and your motor cortex for guitar (fretting the note). When all three align, you've established a reference point from which to find every other note. The 'singing while playing' confirmation is important because it eliminates uncertainty -- if you can sing the note and fret the note and they're the same, you KNOW you've found it. This certainty is the foundation for the next step." },
        { text: "From the starting note, figure out each subsequent note by singing it and then finding it on guitar. Move through the 4-bar phrase note by note. For each note, ask: 'Is this higher or lower than the previous note? By how much? A small step? A big leap?' Then verify on guitar.", why: "Sequential note-finding trains RELATIVE pitch -- the ability to hear intervals between notes. This is different from (and more useful than) absolute pitch identification. When you ask 'higher or lower? by how much?' you're explicitly training interval recognition. Over time, common intervals become instantly recognizable: a step up sounds like the beginning of 'Do-Re-Mi,' a leap of a 4th sounds like 'Here Comes the Bride,' a leap of a 5th sounds like 'Star Wars.' These reference songs create landmarks in your interval map that make future dictation faster." },
        { text: "Write down the scale degrees of your transcribed melody. Use numbers: 1 = tonic, 2 = one step up, etc. Or use solfege if you know it. Or just write the note names. The format doesn't matter -- what matters is converting the heard melody into a symbolic representation that you can READ back.", why: "Written transcription converts implicit knowledge (I can hum this melody) into explicit knowledge (I know the melody is 1-3-5-4-3-2-1). This conversion is valuable because explicit knowledge is more flexible: you can transpose it (play it in a different key by applying the same scale-degree pattern to a different tonic), you can analyze it (notice that the melody emphasizes the 3rd and 5th), and you can discuss it with other musicians. The act of writing also forces precision -- you can't be vague about a note when you have to choose a specific symbol for it." },
        { text: "Sing the 4-bar phrase from your written transcription, WITHOUT listening to the original. Can you reconstruct the melody from your notation? Compare to the original. How close were you? The discrepancies show you where your ear is weaker -- those are the intervals or rhythmic patterns that need more practice.", why: "Singing from your transcription closes the loop: you heard a melody, extracted its structure, wrote it down, and now you're regenerating it from the written representation. This full cycle (hear -> analyze -> notate -> reproduce) is the complete melodic dictation skill. Comparing to the original provides feedback that calibrates your ear: if you consistently miss the same interval (say, minor 3rds sound like major 2nds to your ear), that specific interval becomes a targeted practice area. Most musicians have 1-2 'problem intervals' that respond quickly to focused training." },
        { text: "Repeat with a different 4-bar phrase from the same song. The second time is always faster because you already know the key, the style, and the singer's tendencies. Track your speed: how many minutes does it take to dictate 4 bars? This time will decrease dramatically over the coming weeks.", why: "Speed tracking provides concrete evidence of skill development. Most people start at 5-10 minutes per 4 bars and, with practice, get to 1-2 minutes. This speed increase reflects the automation of the component skills: pitch matching becomes instant instead of tentative, interval recognition becomes reflexive instead of deliberate, and pattern recognition kicks in (you start recognizing common melodic patterns like the 1-2-3 scale fragment or the 5-1 cadential resolution without analyzing each note individually). The speed improvement is usually non-linear -- slow progress for the first few sessions, then a sudden leap when the skills begin to automate." }
      ],
      feel: "Like a detective solving a musical puzzle. Each note you find is a clue that leads to the next. The moment when you sing the whole phrase from your transcription and it matches the original is deeply satisfying -- you cracked the code with your ear alone.",
      wrong: "If you absolutely cannot find the starting note, try this: sing any comfortable note, then play the song -- does your note sound 'in' the key? If yes, you're in the right area; search nearby. If no, try a different note. If the whole process feels impossibly hard, choose an EASIER song with a simpler, more stepwise melody. Build skill with simple melodies before tackling complex ones.",
      sarah: "Gene, melodic dictation is the core skill that makes everything else in this level possible. It's like learning to read in a new language -- frustrating at first, then progressively easier, then suddenly fluent. Your years of listening to melodically rich music (Tinariwen's pentatonic vocal lines, Khruangbin's minimalist melodies) have pre-loaded your ear with a huge library of patterns. Dictation teaches you to access that library consciously.",
      metronome: 80,
      levelUp: "Transcribe a 4-bar melody by ear in under 5 minutes, with correct contour and most intervals accurate, singable from written notation."
    },
    {
      id: "v13e4", time: 4, title: "Style Absorption: DOPE LEMON Study", type: "vocal",
      what: "Deep dive into one DOPE LEMON track. Learn the vocal melody by ear. Then study the DELIVERY: the breathiness, the lazy timing, the vowel shapes, the dynamic choices. Imitate the delivery exactly -- not just the notes, but the STYLE. Record yourself and compare. This is how singers develop a vocabulary of vocal colors.",
      setup: "DOPE LEMON track queued (suggestion: 'Marinade' or 'Uptown Folks' or any track Gene connects with). Headphones. Guitar. Recording setup. Give this exercise your full attention.",
      referencePitches: getPitchRange("E3", "A4"),
      pianoKeys: { notes: ["E3", "A3", "C4", "E4"], label: "Song Reference", range: ["E3", "E4"] },
      tracks: [{ name: "Deep Soul Groove 80", src: "/deep-soul-groove-80.mp3" }],
      recorder: true,
      steps: [
        { text: "Learn the verse melody by ear using the 6-step method from v13e1. Take as long as you need. This is not a speed exercise -- accuracy matters more than efficiency here. Once you can sing the verse melody from memory without the track playing, move on.", why: "The melody has to be SOLID in your memory before you can focus on delivery. If you're still figuring out notes while trying to imitate the style, you're splitting cognitive resources and neither task gets done well. This is the principle of 'layered learning' -- master each dimension separately, then combine them. The melody is the foundation layer. Everything else (timing, dynamics, texture, vowel shapes) is built on top of a melody you can sing on autopilot." },
        { text: "Now listen to the DOPE LEMON track again, but focus ONLY on the vocal delivery. Ignore the notes -- you already know them. Listen for: Breathiness (how much air in the tone? a LOT -- DOPE LEMON vocals are extremely airy). Timing (behind the beat? on the beat? the answer is BEHIND -- almost lazily late). Vowel shapes (open and wide? narrow and focused? they're relaxed and wide, like a yawn). Dynamic range (barely-there to medium -- never belting).", why: "Delivery analysis separates the WHAT (melody) from the HOW (style). This distinction is crucial because two singers singing the same notes with different delivery choices create completely different emotional experiences. DOPE LEMON's Angus Stone is a masterclass in 'less is more' vocal delivery: the extreme breathiness communicates vulnerability and intimacy, the behind-the-beat timing communicates ease and confidence, the relaxed vowels communicate a lack of effort (which paradoxically requires great control). By analyzing each element separately, you can learn to reproduce each one deliberately." },
        { text: "Imitation time. Sing the verse melody with DOPE LEMON's delivery. Exaggerate each element: MORE breathy than the original. MORE behind the beat. MORE relaxed vowels. MORE dynamic restraint (barely singing, almost whispering). Exaggeration teaches your muscles the extreme range; you'll dial it back later.", why: "Exaggeration is a proven technique from vocal pedagogy and acting training. When you exaggerate a quality, your muscles learn the DIRECTION of the adjustment more clearly. If you try to be 'slightly more breathy,' your habitual vocal production tends to pull you back to your default. If you go MAXIMALLY breathy, you discover new territory in your vocal mechanism that you didn't know existed. The dial-back comes naturally: once you know where 'maximum breathy' lives, you can find 'DOPE LEMON-level breathy' easily because it's somewhere between your default and the maximum." },
        { text: "Record yourself singing the verse with the DOPE LEMON delivery. Then play the original and your version back-to-back. Listen for the GAPS: where does your delivery differ from the original? Common gaps: not enough breathiness (most singers under-commit to air), timing too on-the-beat (behind-the-beat feels wrong until you hear it back), vowels too tight (relax the jaw more).", why: "The back-to-back comparison is the fastest path to delivery accuracy because it leverages your ear's natural ability to detect differences. When you hear the original followed immediately by your version, the gaps are obvious in a way they're not when you listen to either recording alone. This is the 'A/B comparison' technique used in audio engineering, acting coaching, and accent training. The gaps you identify become specific, targetable adjustments: 'more air on the A vowel,' 'delay the downbeat entrance by an 8th note,' 'drop the jaw more on the word ocean.'" },
        { text: "Second take: record the verse again, this time addressing the specific gaps you identified. Then A/B compare again. Iterate until your delivery is in the same BALLPARK as the original. You're not trying for a perfect imitation -- you're trying to capture the ESSENCE of the vocal approach.", why: "Iterative refinement with A/B comparison is the fastest feedback loop for style absorption. Each iteration narrows the gap between your delivery and the target. But the goal isn't a perfect copy -- it's UNDERSTANDING. Once you can reproduce the DOPE LEMON delivery at will, you OWN that vocal color. It becomes part of your palette, available whenever a song or moment calls for that breathy, lazy, intimate quality. You're not learning to impersonate Angus Stone; you're learning a vocal technique that he happens to exemplify." },
        { text: "Final step: sing the verse in YOUR natural delivery, then switch to the DOPE LEMON delivery mid-phrase. Can you switch on command? If yes, you've ABSORBED the style -- it's now a choice, not an imitation. Record the switch for your reference.", why: "The on-command switch is the acid test of absorption vs. imitation. An imitator can do the voice but can't switch in and out of it seamlessly. An absorber can access the vocal color as easily as changing their tone of voice in conversation (from casual to serious, from playful to sincere). The mid-phrase switch is particularly telling because it requires both vocal colors to be accessible simultaneously in your motor memory. If you can switch cleanly, the style is INTERNALIZED -- stored in procedural memory alongside your default voice, available on demand." },
        { text: "Document what you learned: write down the 3-4 key delivery characteristics of the DOPE LEMON style in your own words (e.g., 'extreme breathiness, behind-beat timing, jaw-drop vowels, whisper dynamics'). This becomes a reference card you can consult when you want to access this vocal color in your own songs.", why: "Explicit documentation converts embodied knowledge into referenceable knowledge. Without documentation, the style absorption fades from conscious accessibility over time -- you might still be able to do it, but you won't think to use it. With documentation, you have a prompt: next time you're recording a verse that wants intimacy, you can look at your DOPE LEMON card and deliberately access that vocal color. Over multiple levels of this kind, you'll build a library of vocal color reference cards that represents your full stylistic range." }
      ],
      feel: "Like becoming a character actor. For 15 minutes, you're not Gene -- you're channeling a vocal approach. Then you step back to yourself, but now you have a new voice in your repertoire. It should feel like learning a new accent: unfamiliar at first, then surprisingly natural.",
      wrong: "If you can't get the breathiness, try this: hold a piece of paper in front of your mouth and sing. The paper should move from the air -- if it doesn't, you're not using enough breath. If you can't get behind the beat, try singing AFTER the note in the track, not with it -- deliberately late. If it all sounds the same as your natural voice, you're not exaggerating enough.",
      sarah: "Gene, DOPE LEMON's vocal style is probably the closest existing reference to your natural sweet spot -- that breathy, laid-back, Pacific-golden delivery. This exercise isn't about becoming someone else; it's about taking something you already resonate with and making it a CONSCIOUS tool. When you can access the DOPE LEMON breathiness on command, you have a vocal color that's perfect for your intimate, golden-hour songwriting voice.",
      levelUp: "DOPE LEMON-style delivery reproduced convincingly on a learned-by-ear melody, switchable on command, with documented delivery characteristics."
    },
    {
      id: "v13e5", time: 4, title: "Style Absorption: Allah-Las Study", type: "vocal",
      what: "Same deep-dive approach with an Allah-Las track. Different vocal aesthetic: straighter tone, more psych-surf float, less personal and more textural. The contrast with DOPE LEMON teaches you that vocal 'style' isn't one thing -- it's a constellation of choices, and different choices create different emotional worlds.",
      setup: "Allah-Las track queued (suggestion: 'Tell Me' or 'Catamaran' or any track with clear vocals). Headphones. Guitar. Recording setup.",
      referencePitches: getPitchRange("E3", "A4"),
      pianoKeys: { notes: ["E3", "A3", "C4", "E4"], label: "Song Reference", range: ["E3", "E4"] },
      tracks: [{ name: "Surf Rock 120", src: "/surf-rock-120.mp3" }],
      recorder: true,
      steps: [
        { text: "Learn the verse melody by ear. Allah-Las melodies tend to be more modal and repetitive than DOPE LEMON -- fewer notes, simpler contours, more reliance on 2-3 note figures. This simplicity is deceptive: the style lives in the DELIVERY, not the melody. Once you have the melody solid, move on.", why: "Allah-Las' vocal melodies are often pentatonic or modal fragments that repeat with slight variation -- a style inherited from 60s garage and psych rock. The simplicity of the melody makes the delivery ALL-important: a simple melody sung with the wrong delivery sounds boring; the same melody with the right delivery sounds hypnotic. This is the opposite of more melodically complex music where the notes themselves carry more of the interest. For Gene, whose songwriting tends toward simple, vibe-driven melodies, understanding how to make simplicity compelling through delivery is a critical skill." },
        { text: "Focus listening on the Allah-Las vocal delivery. Contrast with DOPE LEMON: Where DOPE LEMON is breathy, Allah-Las is DRIER -- less air, more tone. Where DOPE LEMON is behind the beat, Allah-Las is more ON the beat or slightly ahead -- more driving, less lazy. Where DOPE LEMON is intimate and close, Allah-Las is DISTANT and atmospheric -- the voice sits IN the mix rather than in front of it. Vowels are more closed ('ooh' and 'eh' rather than wide-open 'ah').", why: "Comparative analysis between two styles is exponentially more educational than studying either style alone. By contrasting DOPE LEMON and Allah-Las on the same dimensions (breathiness, timing, vowel shapes, spatial positioning), you're learning that each dimension is a SPECTRUM with a range of options, not a binary choice. DOPE LEMON sits at the breathy end of the breathiness spectrum; Allah-Las sits closer to the dry end. Neither is 'correct' -- they're different aesthetic choices for different emotional purposes. This dimensional thinking transforms style from something mysterious ('they just sound different') to something analyzable and reproducible." },
        { text: "Imitate the Allah-Las delivery. Key characteristics: (1) Straighter tone -- minimal vibrato, almost no pitch variation within sustained notes. (2) Spatial recession -- sing as if you're 10 feet from the mic instead of 2 inches. Less breathy, more projected but not loud. (3) Emotional restraint -- the voice doesn't emote; it states. (4) Rhythmic precision -- locked to the beat, not floating behind it. Exaggerate each element.", why: "The Allah-Las vocal approach belongs to a tradition of 'voice as texture' that runs from the Velvet Underground through Stereolab to modern psych-rock. In this tradition, the voice is not the star of the show -- it's one element in a sonic landscape. Achieving this requires RESTRAINT: the singer must resist the urge to emote, project, or dominate the mix. For many singers, restraint is harder than expression because it feels like holding back. But restraint IS an expression -- it communicates cool, distance, mystery. The exaggeration step is important because most singers under-do restraint; they need to go PAST the target to calibrate." },
        { text: "Record yourself with the Allah-Las delivery. A/B compare with the original, focusing on the same gaps as before: tone quality, timing relationship to the beat, emotional temperature, spatial positioning. Make adjustments and re-record.", why: "The A/B comparison works the same way as in the DOPE LEMON exercise, but you'll notice DIFFERENT gaps because you're targeting different qualities. Common gaps in Allah-Las style absorption: too much vibrato (the natural voice wants to waver; psych vocals need to be steady), too much emotional investment (the natural instinct is to 'mean it'; psych vocals need to be cooler), and timing too loose (the natural sway behind the beat needs to be reined in to match the driving psych-rock pulse). Each identified gap is a specific motor adjustment." },
        { text: "Now the critical comparison: sing the same Allah-Las melody with the DOPE LEMON delivery. Then switch to the Allah-Las delivery. Back and forth. Feel the difference in your body: DOPE LEMON is relaxed jaw, slow breath, behind the beat. Allah-Las is controlled jaw, steady breath, on the beat. Same notes, completely different emotional worlds.", why: "Switching between two absorbed styles on the same melody is the most powerful demonstration of delivery as an independent musical dimension. It proves -- in your own voice, in real time -- that the same notes can communicate intimacy OR distance, warmth OR cool, presence OR atmosphere, depending entirely on delivery choices. This understanding is transformative for songwriting: when you write a song, you're no longer locked into one vocal approach. You can CHOOSE the delivery that best serves each section's emotional intention. Verse in DOPE LEMON style, chorus in Allah-Las style? That's a valid artistic choice you can now execute." },
        { text: "Document the Allah-Las delivery characteristics alongside your DOPE LEMON notes. Now you have two vocal color reference cards. The contrast between them defines a RANGE -- your voice can operate anywhere between these two poles, and at any point along the spectrum.", why: "Two reference points define a line; three or more define a space. With DOPE LEMON and Allah-Las documented, you have a one-dimensional spectrum from 'breathy-intimate-behind-beat' to 'dry-atmospheric-on-beat.' Future style absorptions (Skinshape, Tinariwen, Khruangbin) will add more dimensions, creating a multi-dimensional vocal style space that you can navigate at will. This is the long-term goal: not to impersonate anyone but to have a rich vocabulary of vocal delivery options that you deploy based on the emotional needs of each song and each moment." }
      ],
      feel: "The Allah-Las style should feel COOLER than DOPE LEMON -- less personal, more atmospheric. Like you're part of a landscape rather than telling a story. The voice becomes a texture, like a guitar effect or a reverb tail. When you switch between the two styles, the emotional temperature change should be palpable.",
      wrong: "If you keep adding vibrato (natural tendency), try singing while holding a slight smile -- this raises the soft palate and stabilizes pitch. If you sound too 'present' (not atmospheric enough), try singing while imagining you're in a large room, 20 feet from the listener. Spatial imagination affects vocal production in measurable ways. If the restraint feels 'boring,' lean into that -- psych-rock vocal restraint is specifically about embracing the understated.",
      sarah: "Gene, the Allah-Las vocal approach might feel less 'you' than the DOPE LEMON style -- and that's exactly why it's valuable. It expands your range. The psych-surf vocal float is a tool you'll reach for when a song needs atmosphere more than intimacy. And here's the secret: mixing DOPE LEMON warmth with Allah-Las distance creates a vocal style that sounds like neither artist -- it sounds like Gene.",
      levelUp: "Allah-Las-style delivery reproduced convincingly, switchable on command with DOPE LEMON style, with documented delivery characteristics."
    },
    {
      id: "v13e6", time: 3, title: "Transposing to Your Key", type: "vocal",
      what: "Take a song you've learned by ear and find the key where it sits most comfortably in your range. Gene's sweet spot is E3-A4, with the passaggio around A3-B3. Every song should be evaluated: does the original key work for MY voice, or do I need to transpose? This is a critical skill that many singers never learn, leading to years of fighting songs in the wrong key.",
      setup: "Guitar tuned. A song you've already learned the melody for (from earlier exercises). Capo optional but helpful.",
      referencePitches: getPitchRange("E3", "A4"),
      pianoKeys: { notes: ["E3", "A3", "C4", "E4"], label: "Song Reference", range: ["E3", "E4"] },
      pitchContour: true,
      recorder: true,
      steps: [
        { text: "Sing the melody you've learned in its ORIGINAL key. Notice: where does it feel comfortable? Where does it strain? Where does it go too low (notes that disappear into your chest) or too high (notes where you tighten, push, or flip to falsetto unexpectedly)? Mark the uncomfortable moments.", why: "This assessment reveals the conflict between the original artist's voice and Gene's voice. Every singer has a unique range, passaggio location, and timbre profile. A song written by a baritone will sit differently in a tenor voice, and a song written by a high tenor will sit differently in Gene's mid-tenor range. The uncomfortable moments are the data points: if the melody dips below E3 (Gene's comfortable floor) or climbs above A4 (approaching the strain zone), the key needs to change. This isn't a limitation -- it's a fundamental reality that every professional singer navigates." },
        { text: "Try the melody a half-step higher. How does it feel? Better or worse? Then try a half-step lower. Keep exploring: up a whole step, down a whole step, up a minor 3rd. Use your capo to shift the guitar (capo 1 = up a half step, etc.) or re-finger the chords in the new key.", why: "Systematic key exploration is more reliable than guessing because the 'right' key isn't always obvious. A song might feel too low in the original key but too high when transposed up by a whole step -- meaning the ideal key is a half step up (the smallest possible change). The capo makes this exploration easy on guitar: you can test any key without learning new chord shapes. The goal is to find the key where the ENTIRE melody sits within Gene's comfortable range (E3-A4) with the climax notes approaching but not exceeding A4." },
        { text: "For each key you try, pay specific attention to the CLIMAX NOTE -- the highest point of the melody (usually in the chorus). In the ideal key, the climax note should land between F#4 and A4 for Gene: high enough to feel exciting and energized, not so high that it requires strain or flipping to falsetto.", why: "The climax note determines the emotional ceiling of the song. If it's too low, the chorus lacks energy and the audience doesn't feel the lift. If it's too high, the singer strains and the audience feels tension instead of excitement. The ideal climax zone for Gene (F#4-A4) is above his comfortable speaking range (which makes it feel 'elevated' and special) but below his strain threshold (which means it sounds powerful rather than effortful). This is the 'sweet spot ceiling' -- the highest note that sounds free and strong." },
        { text: "Also check the LOWEST NOTE. In the ideal key, the lowest note should be at or above E3 -- below that, Gene's voice loses projection and clarity, and the notes start to sound muddy. If the lowest note is below E3, transpose UP even if the high notes were comfortable.", why: "The floor matters as much as the ceiling. Low notes that are below a singer's comfortable range lack harmonic richness because the vocal folds can't vibrate fully at those frequencies for that particular voice. The resulting sound is breathy, thin, and projects poorly -- which undermines the musical impact of the low section (usually the verse). Many singers focus only on the high notes when choosing a key and end up with verses that sound weak. Checking both extremes ensures the ENTIRE melody sits in the voice's productive range." },
        { text: "Once you've found the ideal key: sing the full melody in this key. Record it. It should feel EASY -- not effortless (you still need to support and project) but UNSTRAINED. Compare this recording to the one in the original key. The difference in vocal quality is usually dramatic.", why: "The comparison recording is the proof. In the wrong key, the voice sounds tight on high notes and weak on low notes. In the right key, the voice sounds even, warm, and in control throughout the range. Listeners hear this difference even if they can't articulate it -- a voice in its right key sounds 'confident' and 'natural,' while a voice in the wrong key sounds 'trying hard' or 'thin.' This single adjustment -- finding the right key -- can transform a mediocre-sounding performance into a professional one." },
        { text: "Write down the transposition: 'Original key: X. My key: Y. Capo: Z.' Add this to your song notes. Every song in your repertoire should have a documented 'Gene key.' Over time, you'll notice patterns: most songs in a certain key group need to be transposed the same amount. This gives you a shortcut for future transpositions.", why: "Documentation creates efficiency. If you discover that you consistently transpose songs down by a whole step, you can start there when learning new songs instead of exploring every option. The pattern recognition also deepens your self-knowledge as a singer: you'll learn that you sound best when melodies peak around G4-A4 and floor around E3-F#3, which becomes a compositional guideline for writing original songs. The repertoire documentation is also the beginning of your set list -- every song with a documented 'Gene key' is a performance-ready piece." }
      ],
      feel: "Finding the right key should feel like putting on shoes that fit. The melody that was slightly uncomfortable in the original key suddenly feels natural and expressive. The high notes have energy instead of strain. The low notes have warmth instead of mud.",
      wrong: "If no key feels right, the melody might have a range wider than your comfortable range (more than an octave and a half). In that case, you may need to adapt the melody: take the lowest notes up an octave, or the highest notes down. This is legitimate musical arrangement, not cheating. If the song sounds 'wrong' in a new key, give it time -- your ear is accustomed to the original key. After singing in the new key 5-10 times, it will sound normal.",
      sarah: "Gene, transposition is a superpower that most amateur singers ignore. They fight songs in the original key because they think transposing is 'cheating.' But every professional singer transposes constantly -- that's what keys are for. Your voice is an instrument with a specific range, and choosing the right key is like choosing the right guitar string for a melody. It's not cheating; it's competence.",
      metronome: 80,
      levelUp: "Song melody performed in Gene's optimal key (E3-A4 range, climax between F#4-A4), with documented key transposition and audibly improved vocal quality vs. original key."
    },
    {
      id: "v13e7", time: 4, title: "Making a Song Your Own", type: "vocal",
      what: "Take a song you've learned by ear and change ONE element to make it personal: the rhythm (behind-the-beat delivery), the dynamics (whisper verse, full chorus), or the texture (add breathiness, add falsetto breaks). This is the art of INTERPRETATION -- the difference between a cover and a performance. Making covers personal is what separates artists from karaoke singers.",
      setup: "A song you've learned (melody + chords). Guitar. Recording setup. Quiet space for concentrated creative work.",
      referencePitches: getPitchRange("E3", "A4"),
      pianoKeys: { notes: ["E3", "A3", "C4", "E4"], label: "Song Reference", range: ["E3", "E4"] },
      tracks: [{ name: "Khruangbin Style 80", src: "/khruangbin-style-80.mp3" }],
      recorder: true,
      steps: [
        { text: "Sing the learned song as close to the original as you can. This is your 'faithful cover' version. Record it. This is the baseline that you'll modify. Note: even your 'faithful' version already differs from the original because your voice is different from the original singer's. Those unintentional differences are the seed of your interpretation.", why: "The faithful cover establishes what you're starting from. It's important to record this baseline because after you make intentional changes, you need to be able to hear what changed. The observation about unintentional differences is significant: your natural vocal tendencies (Gene's laid-back timing, his tenor timbre, his tendency toward breathiness) are already present in the 'faithful' version. These aren't mistakes -- they're the beginning of your personal interpretation. Style isn't something you add to a song; it's something that's already present in how your voice naturally interacts with the melody." },
        { text: "Choose ONE element to change. Options: (A) TIMING -- shift the entire vocal delivery behind the beat by an 8th note. Every phrase starts slightly later than 'on time.' This creates a relaxed, confident feel. (B) DYNAMICS -- sing the verse at half volume (breathy, intimate) and the chorus at full volume. This creates a dramatic arc. (C) TEXTURE -- add falsetto breaks on the highest notes, or breathiness on the verse, or a raw edge on the chorus.", why: "Changing only ONE element is a deliberate constraint that produces better results than changing everything at once. When you change one thing, you can hear exactly how that change affects the feel of the song. When you change three things simultaneously, the individual effects blur together and you can't identify what's working. This is the scientific method applied to musical interpretation: change one variable, observe the effect, decide if you like it. The three options (timing, dynamics, texture) correspond to the three most impactful delivery dimensions -- each one alone can transform a song from faithful reproduction to personal statement." },
        { text: "Record the modified version. A/B compare with the faithful cover. Which feels more 'you'? Which tells the emotional story of the song more effectively? Sometimes the faithful version is better -- that's valuable information too. But usually, the modified version has more personality.", why: "The A/B comparison reveals the emotional impact of your interpretive choice. Often, the modified version feels more 'right' even though it's further from the original -- because it's closer to YOUR natural expression. The permission to decide that the faithful version is better prevents the exercise from becoming formulaic: sometimes a song doesn't need your interpretation. But more often, adding one personal element transforms a competent cover into a compelling performance. The key question is not 'does this sound like the original?' but 'does this sound like me singing this song?'" },
        { text: "Try a SECOND modification on top of the first. If you shifted timing, now also shift dynamics. Or texture. How does the song feel with TWO personal choices? Record it. Now you have three versions: faithful, one modification, two modifications. Which is the sweet spot?", why: "Layering modifications tests whether your changes are complementary or conflicting. Behind-the-beat timing + whisper dynamics might create a beautifully intimate verse, or they might remove too much energy. The three-version comparison helps you find the RIGHT AMOUNT of personalization. This mirrors how professional producers work: they try variations and compare. There's no formula for 'how much to change' -- it depends on the song, the artist's taste, and the performance context. Your ear is the final judge." },
        { text: "Final version: record your best interpretation -- the version that feels most 'Gene.' Compare it to the original artist's version one more time. Your version should sound different but EQUALLY valid. Not better or worse -- different. Your version and the original are both legitimate interpretations of the same song.", why: "The frame shift from 'my version is an imperfect copy of theirs' to 'my version is a different interpretation' is one of the most important psychological shifts in a singer's development. It moves you from REPRODUCTION (trying to match the original) to CREATION (making the song yours). This is not arrogance -- it's artistic maturity. Every great cover version in music history (Johnny Cash's 'Hurt,' Jeff Buckley's 'Hallelujah,' Jimi Hendrix's 'All Along the Watchtower') is a radically personal interpretation that stands alongside the original as an independent work of art." },
        { text: "Document your interpretive choices: 'For this song, I shifted timing behind the beat and added breathiness in the verse.' This becomes part of your performance notes. When you revisit this song next week, you won't have to re-discover your interpretation -- it's documented.", why: "Performance documentation ensures that your interpretive discoveries are preserved. Without notes, you'll forget the specific choices that made the last performance work, and you'll either revert to the faithful cover or make different (possibly less effective) choices next time. Professional musicians keep detailed performance notes for exactly this reason. Your documentation doesn't need to be long -- 2-3 sentences about the key interpretive choices. Over time, this creates a performance handbook for your repertoire." }
      ],
      feel: "This should feel like finding your voice WITHIN someone else's song. The melody is theirs, the chords are theirs, but the delivery is YOURS. When it clicks, the song stops feeling like a cover and starts feeling like a conversation between you and the original artist.",
      wrong: "If the modifications sound gimmicky rather than natural, you might be changing too much or too dramatically. Pull back. The goal is subtle personalization, not radical reinterpretation (that comes with more experience). If you can't decide which element to change, try all three separately and see which one makes the biggest positive difference.",
      sarah: "Gene, making a song your own is the moment where 'learning songs' becomes 'building a repertoire.' A repertoire isn't a list of songs you can copy -- it's a collection of songs you've INHABITED, songs that sound like Gene even though someone else wrote them. Your behind-the-beat, golden-hour, breathy-verse delivery is already a signature style in the making. This exercise teaches you to apply it deliberately.",
      levelUp: "Learned song performed with at least one intentional interpretive modification that makes it sound personally delivered rather than faithfully reproduced, with documented performance choices."
    },
    {
      id: "v13e8", time: 3, title: "Recording Self-Assessment Protocol", type: "record",
      what: "Record yourself singing a learned song. Listen back with a structured rubric: Pitch (1-5), Timing (1-5), Delivery (1-5), Guitar coordination (1-5), Emotional connection (1-5). Identify the lowest score. Focus next practice on that dimension. This transforms vague self-criticism into targeted improvement.",
      setup: "Phone or recording device. A song you can perform (even imperfectly). The rubric below. Honest ears.",
      referencePitches: getPitchRange("E3", "A4"),
      pianoKeys: { notes: ["E3", "A3", "C4", "E4"], label: "Song Reference", range: ["E3", "E4"] },
      recorder: true,
      pitchContour: true,
      steps: [
        { text: "Record a full performance of a song -- verse, chorus, at minimum. Don't warm up excessively; this should capture your TYPICAL performance level, not your best possible performance. Think of it as a snapshot of where you are today.", why: "Recording your typical performance rather than your best performance gives you accurate diagnostic data. If you warm up for 20 minutes and record your peak version, the assessment won't reflect what you sound like at a gig (where you might be cold, nervous, or distracted). The snapshot approach also reduces performance anxiety around recording -- you're not trying to nail it, you're trying to DOCUMENT it." },
        { text: "Listen back with the rubric. Score each dimension 1-5: PITCH (1 = frequently off-key; 5 = consistently accurate, intentional pitch choices). TIMING (1 = frequently rushing/dragging; 5 = locked to the groove, intentional timing deviations). DELIVERY (1 = flat, one-dimensional; 5 = dynamic, varied, emotionally appropriate). GUITAR COORDINATION (1 = guitar falls apart when singing; 5 = guitar autopilot, zero interference). EMOTIONAL CONNECTION (1 = going through the motions; 5 = genuinely feeling the song, it comes through in the voice).", why: "The 5-dimension rubric prevents the common pattern of vague self-criticism ('that sucked') and replaces it with specific, actionable assessment ('pitch was 4, timing was 2, delivery was 3, guitar was 4, emotion was 3'). Each dimension corresponds to a different training area: pitch connects to Levels 2 and 4, timing to Level 3, delivery to Level 6 and the absorption exercises in this level, guitar coordination to Level 8, and emotional connection to everything. The numerical scores enable TRACKING over time -- you can see which dimensions improve and which plateau." },
        { text: "Identify your LOWEST score. This is your priority area. Not the area you most enjoy practicing -- the area that needs the most work. The lowest score has the most room for improvement and will produce the most noticeable change in your overall performance quality.", why: "The weakest-link principle from systems theory: the overall quality of a performance is limited by its weakest dimension, not elevated by its strongest. A singer with perfect pitch but terrible timing sounds worse overall than a singer with good pitch and good timing. Targeting the lowest score is the highest-leverage practice strategy because small improvements in the weakest area produce larger overall quality gains than large improvements in already-strong areas. This is counterintuitive because we naturally gravitate toward practicing what we're already good at (it feels rewarding) and avoid what we're weak at (it feels frustrating)." },
        { text: "Design a specific practice plan for your lowest-scored dimension. If timing is lowest: practice with a metronome, focus on rhythmic exercises from Level 3. If delivery is lowest: revisit the style absorption exercises from this level. If guitar coordination is lowest: simplify the guitar part until it's truly autopilot. Write the plan down.", why: "A written practice plan converts assessment into action. Without a plan, the assessment is just self-awareness with no follow-through. The plan should be SPECIFIC and TIME-BOUND: 'For the next week, I'll spend 10 minutes per session on timing exercises before working on songs.' Vague plans ('I should work on timing') produce vague results. Specific plans ('Metronome at 80 BPM, quarter-note claps, then singing verse of Song X locked to the click') produce specific improvements." },
        { text: "Re-record the same song in one week. Score again. Compare scores. Any improvement? Even 0.5 points in the targeted dimension is meaningful progress. If no improvement, the practice plan might need adjustment -- more time, different exercises, or a different approach to the weak area.", why: "The weekly re-assessment closes the improvement loop: assess -> plan -> practice -> reassess. This cycle is the fundamental unit of deliberate practice. The one-week interval is long enough for neural consolidation (the brain needs sleep cycles to solidify new motor patterns) but short enough that you haven't forgotten what you were working on. The permission for 0.5-point improvements sets a realistic expectation -- skill development is incremental, and small gains compound over weeks into significant improvement." },
        { text: "Over time, build a log of your assessments: Date, Song, Pitch score, Timing score, Delivery score, Guitar score, Emotion score. Look for trends. Which dimensions are improving? Which are stuck? The data tells you where your practice is effective and where you need a different approach.", why: "The assessment log transforms subjective feeling ('I think I'm getting better?') into objective tracking ('My timing scores have improved from 2.5 to 3.5 over 4 weeks, but delivery has plateaued at 3'). This data-driven approach is uncommon in music education but standard in sports coaching, academic research, and professional development. It works because it provides evidence of progress (motivating) and evidence of plateaus (informative). The log also creates accountability: if you skip assessments, the gap in the log is visible. If you skip practice, the stagnant scores are visible." }
      ],
      feel: "This should feel clinical in a good way -- like a doctor's checkup, not a judgment. The rubric removes the emotional charge from self-assessment and replaces it with specific, actionable information.",
      wrong: "If you're scoring everything 1 or 2, you're being too harsh -- recalibrate by remembering that 3 is 'competent, room for improvement,' which is where most intermediate musicians live. If you're scoring everything 4 or 5, you're being too generous -- record yourself performing for a friend or family member and see if your assessment holds up with an audience present.",
      sarah: "Gene, this protocol is your quality control system. Every musician who gets better has some version of this -- a way to honestly assess where they are and systematically work on what needs improvement. The rubric takes the emotion out of it. You're not asking 'am I good?' -- you're asking 'which specific skill needs the most attention this week?' That's a much more productive question.",
      levelUp: "Completed self-assessment with documented scores across all 5 dimensions, identified lowest score, and created a specific practice plan targeting that dimension."
    },
    {
      id: "v13e9", time: 3, title: "Repertoire Building", type: "vocal",
      what: "Build a list of 5-10 songs Gene can perform. Criteria: in his key (E3-A4), playable on guitar, suits his vocal style, emotionally connected. This is the beginning of a set list -- the curated collection of songs that define Gene as a performing musician.",
      setup: "Guitar. Phone/speaker for reference. Paper and pen for the list. Thinking cap on.",
      referencePitches: getPitchRange("E3", "A4"),
      pianoKeys: { notes: ["E3", "A3", "C4", "E4"], label: "Song Reference", range: ["E3", "E4"] },
      steps: [
        { text: "Brainstorm a long list of songs you know (or could learn) -- at least 15-20 candidates. Include: songs you've learned in this level, songs you've been playing for years, songs you sing in the car, songs from your 'Songs 2 Learn' playlist. Don't filter yet -- quantity first.", why: "Starting with a long list prevents premature filtering. If you start by looking for 'perfect' songs, you'll overlook good ones. The brainstorm captures everything that's even remotely in your musical world. Songs you sing in the car are particularly valuable data because they represent songs your voice naturally connects with -- you wouldn't sing along if the melody didn't feel good in your voice. The 'Songs 2 Learn' playlist is a curated source of songs you're already drawn to." },
        { text: "Apply the first filter: RANGE. For each song, does the melody fit within E3-A4? If you've already transposed it (from v13e6), note the transposed key. Cross off any song where the melody can't be made to fit your range without radical surgery.", why: "Range is the non-negotiable first filter because no amount of practice will make a melody comfortable if it's outside your physiological range. A song that requires notes above B4 or below D3 will always involve strain or inaudibility, which undermines every other dimension of the performance. The transposition notes from v13e6 make this filter quick for songs you've already processed. For new songs, a rough assessment (can I hum the highest and lowest notes comfortably?) is sufficient at this stage." },
        { text: "Apply the second filter: PLAYABILITY. Can you play the guitar part while singing? Or could you, with a week of practice? Cross off songs where the guitar part is too complex for sing-and-play (for now -- they might come back later as your coordination improves).", why: "Playability is the practical filter. A song that sounds great sung a cappella but falls apart when you add guitar isn't performance-ready. The 'with a week of practice' clause is generous but realistic -- you don't need to be able to play it NOW, but you need to be able to see a path to performing it. Songs with complex fingerpicking or fast chord changes might need to be simplified (strum instead of pick, fewer chord changes) to be playable while singing. Simplification is a legitimate arrangement choice, not a compromise." },
        { text: "Apply the third filter: STYLE FIT. Does the song suit your vocal style? The test: when you sing it, does it sound like a NATURAL EXPRESSION of who you are as a musician, or does it sound like you're doing an impression? Songs that make you sound like yourself pass. Songs that make you sound like you're trying to be someone else don't.", why: "Style fit is the most subjective but most important filter. A song can be in your range and playable but just not 'you.' Gene's style -- laid-back, golden-hour, psych-surf-reggae, breathy and intimate -- suits certain songs better than others. An AC/DC song might be in range and playable but wouldn't fit the style. A Khruangbin or DOPE LEMON or Jack Johnson song would. The test is honest self-assessment: does this song BELONG in my mouth? The answer is a gut feeling that reflects the alignment between the song's emotional world and yours." },
        { text: "Apply the fourth filter: EMOTIONAL CONNECTION. Do you FEEL something when you sing this song? Not just enjoy the melody -- actually connect with the lyric, the story, the emotional landscape. Songs you're emotionally connected to are dramatically more compelling in performance because the emotion is real, not acted.", why: "Emotional connection is the secret ingredient that elevates a competent cover into a memorable performance. Research on audience perception shows that listeners can detect genuine emotional engagement vs. performed emotion with remarkable accuracy -- the voice carries micro-cues (timing fluctuations, dynamic shifts, timbral changes) that are different when the emotion is real. By selecting only songs you genuinely feel, you ensure that your performances have emotional authenticity. This doesn't mean every song has to make you cry; it means every song has to make you FEEL something -- joy, nostalgia, longing, peace." },
        { text: "Your final list should be 5-10 songs. Rank them: which ones are you most excited to perform? Which feel most 'Gene'? The top 3-5 become your core repertoire -- songs you practice regularly and could perform at any time. The rest are your extended repertoire -- songs you know but don't keep in active rotation.", why: "The core/extended split creates a manageable practice load while maintaining a deep bench. Practicing 3-5 songs regularly keeps them performance-ready without consuming all your practice time. The extended repertoire gives you options for variety without requiring active maintenance. Most working musicians operate with a core of 10-15 songs and an extended repertoire of 30-50. You're starting smaller, but the structure is the same. The ranking by excitement is important: you should WANT to play your core repertoire. If practicing a song feels like a chore, it shouldn't be in the core." }
      ],
      feel: "This should feel like curating a gallery -- choosing which pieces represent you. Each song in the final list should make you think 'yes, this is a Gene song.' The list is personal, opinionated, and unapologetic.",
      wrong: "If you can't get to 5 songs, your filters might be too strict -- loosen the playability filter (you can simplify guitar parts) or the style filter (some songs grow on you). If you have 15 songs that all pass, be more selective on emotional connection -- which ones do you MOST want to play?",
      sarah: "Gene, your repertoire is your musical identity. It tells the world (and yourself) who you are as a musician. The songs you choose to learn, adapt, and perform define your artistic voice as surely as the songs you write. A well-curated setlist of covers -- in your key, in your style, with your emotional connection -- is a powerful thing. It's the foundation that your original songs will eventually grow from.",
      levelUp: "Curated list of 5-10 performance-ready songs with documented keys, guitar parts, interpretive choices, and emotional connections."
    },
    {
      id: "v13e10", time: 4, title: "Learn a Song in One Session", type: "vocal",
      what: "Timed exercise: 25 minutes to learn a new song by ear from scratch using the 6-step method. Everything you've practiced in this level comes together under time pressure. This tests the SPEED of your by-ear learning -- how fast can you go from 'never learned this song' to 'can perform it from memory'?",
      setup: "Timer set for 25 minutes. A song you've HEARD but NEVER LEARNED. Guitar. No tabs, no YouTube tutorials, no cheating. Phone/speaker for the reference track. Record the final performance.",
      referencePitches: getPitchRange("E3", "A4"),
      pianoKeys: { notes: ["E3", "A3", "C4", "E4"], label: "Song Reference", range: ["E3", "E4"] },
      recorder: true,
      steps: [
        { text: "Minutes 0-3: LISTEN. Three full listens with the focused protocol from v13e2. You don't have time for 5 separate listens, so combine: Listen 1 = form + feel, Listen 2 = vocal melody, Listen 3 = chords + guitar. Write brief notes between listens.", why: "Under time pressure, the listening phase gets compressed but NOT eliminated. Skipping the listening phase to 'save time' is a false economy -- you'll spend MORE time fumbling with notes you haven't properly heard. Three focused listens in 3 minutes provides enough information to guide the learning process. The notes between listens capture first impressions that you'll refine later." },
        { text: "Minutes 3-5: FIND THE KEY. Locate the tonic on guitar. Play the first chord. Is the song major or minor? Find 2-3 more chords. You don't need ALL the chords -- just enough to accompany the verse. Prioritize the verse because that's where most of the vocal melody learning happens.", why: "Key and basic chords in 2 minutes is aggressive but achievable with practice. The tonic is usually the first or last chord you hear. Major vs. minor is a binary choice. And 2-3 chords can support most pop/rock/folk verses (many are built on just I-IV-V or i-III-VII). The verse-first priority is strategic: if you can play and sing the verse, you have a performable unit even if you run out of time on the chorus." },
        { text: "Minutes 5-15: LEARN THE VERSE MELODY. This is the core of the exercise. Microloop: listen to 2-4 bars, pause, sing back, check on guitar. Move to the next section. Then assemble the full verse. Repeat the full verse from memory 3 times. This should take about 10 minutes.", why: "10 minutes for the verse melody is generous enough to be thorough but tight enough to maintain urgency. The microloop method from v13e1 is the most efficient approach under time pressure because each section is learned to criterion before moving on. The 3 full repetitions from memory are the consolidation step: they move the melody from short-term memory (fragile, will disappear in minutes) to medium-term memory (more stable, will last the session and possibly longer with sleep consolidation)." },
        { text: "Minutes 15-20: LEARN THE CHORUS MELODY. Same microloop approach. The chorus is often simpler than the verse (more repetitive, bigger intervals, more singable). If the chorus is similar to the verse (common in folk and reggae), this goes fast. If it's completely different, prioritize getting the first 4 bars.", why: "The chorus is often more memorable than the verse because it's designed to be catchy -- higher energy, simpler melody, more repetition. This makes it faster to learn by ear. If time runs short, having the first 4 bars of the chorus is enough to create a performable medley: verse -> chorus opening -> return to verse. The strategic prioritization (verse first, chorus second) ensures you always have SOMETHING performable even if you don't finish." },
        { text: "Minutes 20-23: INTEGRATE AND TRANSPOSE. Sing verse + chorus from memory with guitar. If the key doesn't fit your voice, transpose (capo up or down) and run through again. Choose ONE interpretive modification from v13e7 (timing shift, dynamic shift, or texture change). Apply it.", why: "Integration under time pressure tests whether the melody and chords are truly in memory or just barely held in working memory. If the verse-chorus integration falls apart, the melody needs more repetition. The transposition step is crucial -- performing in the wrong key undermines everything. The single interpretive modification transforms this from a dictation exercise into a performance exercise: you're not just reproducing the song, you're making it yours, even under time pressure." },
        { text: "Minutes 23-25: PERFORM AND RECORD. Full performance of verse + chorus (or verse if that's all you got). No stopping. No restarts. This is a timed performance of a song you learned from scratch in 25 minutes. Hit record, play, sing, done.", why: "The final performance under time pressure simulates real-world scenarios where you need to learn something quickly: a jam session where someone calls a song you don't know, a performance where you want to add a new song at the last minute, a recording session where you're learning a melody for the first time. The no-stopping rule is essential because it trains performance resilience -- the ability to keep going even when you're not 100% sure of the next note." },
        { text: "After the timer: listen to your recording. Score it using the 5-dimension rubric from v13e8. Be honest. For a 25-minute learn-by-ear, scores of 2-3 across the board are EXCELLENT. You learned a song from scratch by ear in less than half an hour. That's a real skill.", why: "Calibrating expectations is important for this exercise. A song learned in 25 minutes will not sound as polished as a song practiced for weeks. But the ABILITY to learn quickly by ear is enormously valuable -- it means you can walk into any musical situation, hear a song, and participate. Over time, your 25-minute learning quality will improve as the component skills (pitch matching, interval recognition, chord identification) become faster and more automatic. Track your scores to see this improvement." }
      ],
      feel: "Like a musical speed round. The time pressure creates urgency that sharpens your focus. You don't have time for perfectionism -- you have to make quick decisions and commit. This is exhilarating if you embrace the challenge and frustrating if you resist the imperfection.",
      wrong: "If you run out of time on the verse melody, the song might be too complex for a timed exercise. Choose something simpler next time -- a song with a more repetitive, pentatonic melody. If you can't find the chords at all, skip them and just sing the melody over a single-chord drone. If the final performance falls apart, that's data -- you need more time on the melody before integrating with guitar.",
      sarah: "Gene, this is the test. Everything from Level 13 -- the 6-step method, the focused listening, the ear training, the transposition, the interpretation -- compressed into 25 minutes. It won't be perfect, and it shouldn't be. But the fact that you can learn a song by ear in under half an hour? That puts you ahead of most hobby musicians. And it gets faster every time you do it.",
      metronome: 80,
      levelUp: "New song learned entirely by ear in 25 minutes, performed from memory with guitar accompaniment, scoring at least 2.5 average on the 5-dimension rubric."
    },
    {
      id: "v13e11", time: 4, title: "Level Integration: Complete Song Performance", type: "record",
      what: "Perform a song learned entirely by ear throughout this level. Full arrangement: verse, chorus, any additional sections. Personal interpretation applied. In Gene's key. Recorded and self-assessed. This is the capstone of Level 13 -- proof that you can hear a song, learn it with your ear and your guitar, make it your own, and perform it convincingly.",
      setup: "Full setup: guitar, mic or phone recording, quiet space. The song you feel strongest about from this level's work. Warm up with the 4-7-8 breathing from v10e0 (performance mode).",
      referencePitches: getPitchRange("E3", "A4"),
      pianoKeys: { notes: ["E3", "A3", "C4", "E4"], label: "Song Reference", range: ["E3", "E4"] },
      recorder: true,
      pitchContour: true,
      volumeMeter: true,
      tracks: [
        { name: "Khruangbin Style 80", src: "/khruangbin-style-80.mp3" },
        { name: "Deep Soul Groove 80", src: "/deep-soul-groove-80.mp3" }
      ],
      steps: [
        { text: "Pre-performance: do the performance mode ritual from v10e0. Shake out tension, 4-7-8 breathing, reframe nerves as excitement, set one intention. This performance matters because it's the culmination of a level of focused ear training and interpretation work.", why: "The performance ritual is important because even a 'practice performance' benefits from the psychological preparation. The ritual signals to your brain that this is a performance, not a practice run -- which changes how you approach mistakes (keep going, don't stop), dynamics (project, don't hold back), and emotional engagement (feel it, don't think about it). Over time, the ritual becomes automatic: body scan, breathe, reframe, intend, perform." },
        { text: "Perform the full song. Start to finish. Guitar + voice. Your interpretation -- not a faithful copy, but YOUR version. If you learned a DOPE LEMON song, your version might be slightly different in timing, dynamics, or texture. If you learned an Allah-Las song, your version might be warmer or more intimate than the original. The differences are your interpretation.", why: "The full performance is the test of every skill from this level: the by-ear melody (v13e1), the focused listening (v13e2), the ear training (v13e3), the style absorption (v13e4, v13e5), the transposition (v13e6), the interpretive choices (v13e7), and the performance resilience (v13e10). Each skill contributes to the whole, but in performance they should be invisible -- the audience (even if it's just you) should hear a musician playing a song, not a student demonstrating skills." },
        { text: "If you make a mistake: KEEP GOING. Hum the part. Skip ahead. Simplify the guitar. Do anything except stop. The ability to recover from errors in performance is more important than the ability to play perfectly -- because perfect performances don't exist, but the ILLUSION of effortlessness does.", why: "Error recovery is the most underpracticed performance skill because you can't practice errors on purpose (well, you can, but it feels wrong). What you CAN do is practice the RESPONSE to errors: keep the rhythm going, keep the energy up, keep the facial expression confident, and move to the next section. The audience rarely notices errors unless the performer SHOWS them -- by stopping, grimacing, or restarting. A smooth recovery is actually MORE impressive than a flawless performance because it demonstrates mastery under pressure." },
        { text: "Record the performance. Listen back using the 5-dimension rubric: Pitch (1-5), Timing (1-5), Delivery (1-5), Guitar coordination (1-5), Emotional connection (1-5). Compare these scores to your diagnostic scores from v13e0. How much have you improved?", why: "The pre/post comparison is the most powerful measure of learning in this level. The diagnostic (v13e0) captured your starting point: how you learned songs, how accurate your ear was, how you rated your performance dimensions. This integration exercise captures your ending point. The comparison between the two recordings -- one from before the level, one from after -- should reveal audible growth in ear accuracy, delivery variety, and interpretive confidence. Even if the numerical scores only improve by 1 point per dimension, the qualitative difference between the recordings is usually striking." },
        { text: "Compare your performance to the original artist's version one final time. Not to see how close you got -- to see how different you are. The differences are your STYLE. The places where you departed from the original (intentionally or not) are the places where Gene's musical personality asserted itself. Note those moments.", why: "This final comparison reframes 'differences from the original' as 'expressions of personal style.' Every divergence from the original -- your timing, your dynamic choices, your vocal texture, even your 'errors' -- is data about who you are as a musician. Some of these divergences are intentional interpretive choices (behind-the-beat timing, dynamic contrast). Others are unconscious tendencies (your natural vibrato, your default vowel shapes). Both types contribute to your unique sound. Acknowledging them transforms them from accidents into identity." },
        { text: "Final assessment: Can you now learn a song by ear, in your key, with personal interpretation, and perform it convincingly? If yes, you've completed Level 13. If some dimensions still need work, note them and carry them into Level 14. Either way, add this song to your repertoire list from v13e9.", why: "The honest self-assessment determines readiness for Level 14. The standard isn't perfection -- it's COMPETENCE with PERSONALITY. Can you learn a song by ear? (Competence.) Can you make it sound like you? (Personality.) If both answers are yes, even roughly, you're ready to move on. If one answer is no, that dimension becomes a practice priority in the next level. Adding the song to the repertoire ensures that this level's work produces a tangible, lasting outcome: a new song you can perform." },
        { text: "Repeat the diagnostic from v13e0 with a DIFFERENT song -- one you haven't worked on in this level. Can you learn a new song faster than before? Score yourself on the same 5 dimensions. Document the growth. This is the final proof that the skills transfer to any song, not just the ones you practiced.", why: "Transfer is the ultimate test of learning. If you can only learn songs you've practiced, you've memorized repertoire but haven't developed skill. If you can learn NEW songs faster and better than before, you've developed generalizable by-ear musicianship. The transfer test with a novel song is the strongest evidence of genuine skill development because it eliminates the possibility that you just got better at the specific songs you practiced." }
      ],
      feel: "This should feel like a graduation performance. Not flawless, but confident. Not a copy, but an interpretation. Not practice, but performance. The song belongs to you now -- you heard it, you learned it, you adapted it, and you performed it. That's musicianship.",
      wrong: "If the performance falls apart completely, you may have chosen a song that's too difficult for your current level. Choose a simpler song and try again. If the performance is solid but the interpretation feels bland, revisit v13e7 and make bolder choices. If the ear skills haven't improved since the diagnostic, you may need to spend more time on melodic dictation (v13e3) before moving on.",
      sarah: "Gene, this is the moment where all the ear training pays off. You can now do something that most musicians can't: hear a song, learn it with your ear, transpose it to your key, add your personal delivery, and perform it. That's not a party trick -- it's the core skill of a musician. Every great singer you admire can do this. Now you can too. And every song you learn from here on out makes the next one faster. Welcome to the club.",
      levelUp: "Complete song performance learned entirely by ear, in Gene's key, with personal interpretation, scored on the 5-dimension rubric, with documented growth from the Level 13 diagnostic."
    }
  ]
};